Title: DateTime.CurrentTimeZone
Category: type
Module Path: effect/DateTime
Export Kind: class
Category Tag: current time zone

Signature: CurrentTimeZone extends ServiceMap.Service<CurrentTimeZone, TimeZone>()( "effect/DateTime/CurrentTimeZone" ) {}

Example:
```ts
import { DateTime, Effect } from "effect"

const program = Effect.gen(function*() {
  // Access the current time zone service
  const zone = yield* DateTime.CurrentTimeZone.asEffect()
  console.log(DateTime.zoneToString(zone))
})

