Title: O.liftNullishOr
Category: function
Module Path: effect/Option
Export Kind: const
Category Tag: Conversions

Description: Lifts a function that may return `null` or `undefined` into one that returns an `Option`. **When to use** - Wrapping existing nullable-returning functions for use in `Option` pipelines **Behavior** - Calls the original function with the given arguments - Wraps the result via fromNullishOr

Signature: liftNullishOr = <A extends ReadonlyArray<unknown>, B>( f: (...a: A) => B ): (...a: A) => Option<NonNullable<B>> => (...a) => fromNullishOr(f(...a))

Example:
```ts
import { Option } from "effect"

const parse = (s: string): number | undefined => {
  const n = parseFloat(s)
  return isNaN(n) ? undefined : n
}

const parseOption = O.liftNullishOr(parse)

console.log(parseOption("1"))
// Output: { _id: 'Option', _tag: 'Some', value: 1 }

console.log(parseOption("not a number"))
// Output: { _id: 'Option', _tag: 'None' }
```

